def _forward_g(self):
    out = self.net_g(self.lq, alpha=self.alpha)
    if isinstance(out, (list, tuple)):
        if len(out) >= 3:
            return out[0], out[1], out[2]
        if len(out) == 2:
            return out[0], out[1], None
    return out, None, None

